from lxml import etree
import io

def process_soap_request(xml_content):
    # Create parser with DTD validation and XXE protection
    parser = etree.XMLParser(
        dtd_validation=True,
        load_dtd=True,
        no_network=False,
        remove_blank_text=True,
        strip_cdata=False,
        recover=False
    )
    
    # Disable external entity loading to prevent XXE attacks
    parser.set_feature(etree.XML_FEATURE_DISALLOW_DOCTYPE_DECL, True)
    
    try:
        # Parse the XML content
        root = etree.fromstring(xml_content, parser)
        
        # Validate SOAP envelope structure
        soap_envelope = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        if soap_envelope is None:
            raise ValueError("Invalid SOAP envelope")
        
        # Extract message body
        soap_body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if soap_body is None:
            raise ValueError("SOAP body not found")
        
        # Return the body content as string
        body_content = etree.tostring(soap_body, encoding='unicode', method='xml')
        
        return body_content
        
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error processing SOAP request: {str(e)}")